import * as React from "react"
import Layout from "../components/layout"
import { graphql } from "gatsby"

import PageTitle from "../components/PageTitle"
import Seo from "../components/seo"

import { faPhoneVolume } from "@fortawesome/free-solid-svg-icons/faPhoneVolume"
import { faEnvelopeOpenText } from "@fortawesome/free-solid-svg-icons/faEnvelopeOpenText"
import { faClock } from "@fortawesome/free-solid-svg-icons/faClock"
import { FaIcon } from "../components/FaIcon"
import Title from "../components/Title"


let fa_icons = [faPhoneVolume, faClock, faEnvelopeOpenText]

export const Head = () => <Seo title="Información de contacto" />

const ContactPage = ({ data }) => (
  <Layout>
    <PageTitle title="Contacto" />

    <section class="construct-contact-page-area section_100">
      <div class="container">
        <div class="row">
          <div class="col-md-10">
            <div class="construct-contact-desc">
              <Title
                section={data.allPagesJson.nodes[0].block1.title}
                title={data.allPagesJson.nodes[0].block1.category}
              />
            </div>
          </div>
        </div>
        <div class="construct-contact-form-bottom">
          <div class="row">
            <div class="col-md-5">
              <div class="contact-form-left">
                {data.allPagesJson.nodes[0].contactInformation.map(
                  (item, i) => {
                    return (
                      <div key={"ci" + i} class="single-contact-left">
                        <div class="contact-icon">

                          <FaIcon
                            icon={fa_icons[i]}
                            fill={"#fbb908"}
                            className="icon text-center"
                            width={24}
                            height={37}
                          />
                        </div>
                        <div class="contact-text">
                          <h4>{item.title}</h4>
                          <p dangerouslySetInnerHTML={{
                            __html: item.data,
                          }}></p>
                          <p>.</p>
                        </div>
                      </div>
                    )
                  }
                )}

              </div>
            </div>
            <div class="col-md-7">
              <div class="construct-contact-form-right">
                <form>
                  <div class="row">
                    <div class="col-md-6">
                      <p>
                        <input type="text" name="name" placeholder="Nombre / Razón Social" />
                      </p>
                    </div>
                    <div class="col-md-6">
                      <p>
                        <input type="email" name="Email" placeholder="Email" />
                      </p>
                    </div>
                  </div>
                  <div class="row">

                    <div class="col-md-6">
                      <p>
                        <input type="tel" name="telefono" placeholder="Teléfono" />
                      </p>
                    </div>
                  </div>
                  <div class="row">
                    <div class="col-md-12">
                      <p>
                        <textarea placeholder="Mensaje..." name="Mensaje" ></textarea>
                      </p>
                      <p>
                        <button type="submit" >enviar</button>
                      </p>
                    </div>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  </Layout>
)

export const query = graphql`
  query {
    allPagesJson(filter: { idPage: { eq: "contacto" } }) {
      nodes {
        idPage
        contactInformation {
          data
          title
        }
        block1 {
          category
          title
        }
        block2 {
          category
          title
        }
      }
    }
  }
`

export default ContactPage
